import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

public class SecureServlet extends HttpServlet {
    protected void doPost(HttpServletRequest request, HttpServletResponse response)
            throws ServletException, IOException {
        String userInput = request.getParameter("input");
        String sanitizedInput = sanitizeInput(userInput);
        String output = "<h1>Welcome " + sanitizedInput + "</h1>";

        response.setContentType("text/html");
        PrintWriter out = response.getWriter();
        out.println(output);
    }

    private String sanitizeInput(String input) {
        // Implement proper input sanitization here
        // For example, you can use OWASP Java HTML Sanitizer or Apache Commons Text library for escaping HTML characters
        // Here is a basic example using Apache Commons Text library:
        return org.apache.commons.text.StringEscapeUtils.escapeHtml4(input);
    }
}

